import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Introducción: Puerta de enlace de IA local | Antigravity Manager","description":"Comprende el posicionamiento central de Antigravity Manager. Proporciona una aplicación de escritorio y una puerta de enlace HTTP local, admite múltiples puntos finales de protocolo y programación de pools de cuentas, y te ayuda a comenzar rápidamente con el proxy inverso local y evitar errores comunes de configuración.","frontmatter":{"title":"Introducción: Puerta de enlace de IA local | Antigravity Manager","sidebarTitle":"¿Qué es la puerta de enlace de IA local?","subtitle":"Qué es Antigravity Tools: convierte «cuentas + protocolos» en una puerta de enlace de IA local","description":"Comprende el posicionamiento central de Antigravity Manager. Proporciona una aplicación de escritorio y una puerta de enlace HTTP local, admite múltiples puntos finales de protocolo y programación de pools de cuentas, y te ayuda a comenzar rápidamente con el proxy inverso local y evitar errores comunes de configuración.","tags":["Primeros pasos","Conceptos","Puerta de enlace local","API Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"es/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}'),r={name:"es/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function n(l,e,c,s,d,u){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="que-es-antigravity-tools-convierte-«cuentas-protocolos»-en-una-puerta-de-enlace-de-ia-local" tabindex="-1">Qué es Antigravity Tools: convierte «cuentas + protocolos» en una puerta de enlace de IA local <a class="header-anchor" href="#que-es-antigravity-tools-convierte-«cuentas-protocolos»-en-una-puerta-de-enlace-de-ia-local" aria-label="Permalink to &quot;Qué es Antigravity Tools: convierte «cuentas + protocolos» en una puerta de enlace de IA local&quot;">​</a></h1><p>Muchos clientes/SDK de IA tienen una barrera de entrada que no radica en «saber llamar a la API», sino en «a qué protocolo conectar realmente, cómo gestionar múltiples cuentas y cómo lograr la recuperación automática ante fallos». Antigravity Tools intenta condensar estas tres cosas en una única puerta de enlace local.</p><h2 id="que-es-antigravity-tools" tabindex="-1">Qué es Antigravity Tools <a class="header-anchor" href="#que-es-antigravity-tools" aria-label="Permalink to &quot;Qué es Antigravity Tools&quot;">​</a></h2><p><strong>Antigravity Tools</strong> es una aplicación de escritorio: gestionas cuentas y configuraciones en la GUI, inicia un servicio de proxy inverso HTTP en tu máquina local, reenvía de forma unificada las solicitudes de diferentes proveedores/protocolos al upstream y convierte las respuestas al formato familiar para el cliente.</p><h2 id="que-puedes-hacer-al-finalizar" tabindex="-1">Qué puedes hacer al finalizar <a class="header-anchor" href="#que-puedes-hacer-al-finalizar" aria-label="Permalink to &quot;Qué puedes hacer al finalizar&quot;">​</a></h2><ul><li>Explicar claramente qué problema resuelve Antigravity Tools (y qué no resuelve)</li><li>Reconocer sus componentes principales: GUI, pool de cuentas, puerta de enlace de proxy inverso HTTP, adaptación de protocolos</li><li>Conocer los límites de seguridad predeterminados (127.0.0.1, puerto, modo de autenticación) y cuándo cambiarlos</li><li>Saber a qué capítulo ir a continuación: instalación, agregar cuenta, iniciar proxy inverso, conectar cliente</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Es posible que hayas encontrado estos problemas:</p><ul><li>El mismo cliente debe admitir tres protocolos: OpenAI/Anthropic/Gemini, y la configuración suele escribirse de forma desordenada</li><li>Tienes múltiples cuentas, pero cambiarlas, rotarlas y reintentar ante límites depende de operaciones manuales</li><li>Cuando falla una solicitud, solo puedes suponer mirando los registros si es «cuenta no válida» o «límite de upstream/capacidad agotada»</li></ul><p>El objetivo de Antigravity Tools es integrar estas «tareas periféricas» en una puerta de enlace local, de modo que tu cliente/SDK solo tenga que preocuparse por una cosa: enviar la solicitud localmente.</p><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>Puedes entenderla como una «puerta de enlace de programación de IA» local compuesta por tres capas:</p><ol><li>GUI (aplicación de escritorio)</li></ol><ul><li>Te permite gestionar cuentas, configuraciones, monitorización y estadísticas.</li><li>La página principal incluye: Dashboard, Accounts, API Proxy, Monitor, Token Stats, Settings.</li></ul><ol start="2"><li>Servicio de proxy inverso HTTP (Axum Server)</li></ol><ul><li>Expone al exterior múltiples puntos finales de protocolos y reenvía las solicitudes al handler correspondiente.</li><li>El servicio de proxy inverso montará capas de autenticación, monitorización de middleware, CORS, Trace, etc.</li></ul><ol start="3"><li>Pool de cuentas y programación (TokenManager, etc.)</li></ol><ul><li>Selecciona cuentas disponibles del pool local, actualiza tokens cuando es necesario y realiza rotación y auto-recuperación.</li></ul><div class="info custom-block"><p class="custom-block-title">¿Qué significa «puerta de enlace local»?</p><p>«Local» aquí tiene su significado literal: el servicio se ejecuta en tu propia máquina, tus clientes (Claude Code, OpenAI SDK, varios clientes de terceros) apuntan la Base URL a <code>http://127.0.0.1:&lt;port&gt;</code>, la solicitud primero llega a la máquina local, y luego Antigravity Tools la reenvía al upstream.</p></div><h2 id="que-puntos-finales-expone" tabindex="-1">Qué puntos finales expone <a class="header-anchor" href="#que-puntos-finales-expone" aria-label="Permalink to &quot;Qué puntos finales expone&quot;">​</a></h2><p>El servicio de proxy inverso registra múltiples conjuntos de puntos finales de protocolo en un Router, puedes memorizar primero estas «entradas»:</p><ul><li>Compatible con OpenAI: <code>/v1/chat/completions</code>, <code>/v1/completions</code>, <code>/v1/responses</code>, <code>/v1/models</code></li><li>Compatible con Anthropic: <code>/v1/messages</code>, <code>/v1/messages/count_tokens</code></li><li>Gemini nativo: <code>/v1beta/models</code>, <code>/v1beta/models/:model</code>, <code>/v1beta/models/:model/countTokens</code></li><li>Verificación de estado: <code>GET /healthz</code></li></ul><p>Si tu cliente puede conectar cualquiera de estos protocolos, teóricamente puedes dirigir las solicitudes a esta puerta de enlace local mediante «cambiar Base URL».</p><h2 id="limites-de-seguridad-predeterminados-no-te-saltes-esto" tabindex="-1">Límites de seguridad predeterminados (no te saltes esto) <a class="header-anchor" href="#limites-de-seguridad-predeterminados-no-te-saltes-esto" aria-label="Permalink to &quot;Límites de seguridad predeterminados (no te saltes esto)&quot;">​</a></h2><p>El mayor problema de este tipo de «proxy inverso local» no suele ser falta de funcionalidad, sino que la expongas sin querer.</p><p>Primero recuerda algunos valores predeterminados (todos provienen de la configuración predeterminada):</p><ul><li>Puerto predeterminado: <code>8045</code></li><li>Solo acceso local predeterminado: <code>allow_lan_access=false</code>, dirección de escucha <code>127.0.0.1</code></li><li>Modo de autenticación predeterminado: <code>auth_mode=off</code> (no requiere que el cliente lleve key)</li><li>De forma predeterminada se generará un <code>api_key</code> de forma <code>sk-...</code> (para que lo actives cuando necesites autenticación)</li></ul><div class="warning custom-block"><p class="custom-block-title">¿Cuándo es obligatorio activar la autenticación?</p><p>Siempre que habilites el acceso a la red de área local (<code>allow_lan_access=true</code>, la dirección de escucha cambia a <code>0.0.0.0</code>), debes activar la autenticación al mismo tiempo y gestionar la API Key como una contraseña.</p></div><h2 id="cuando-usar-antigravity-tools" tabindex="-1">Cuándo usar Antigravity Tools <a class="header-anchor" href="#cuando-usar-antigravity-tools" aria-label="Permalink to &quot;Cuándo usar Antigravity Tools&quot;">​</a></h2><p>Es más adecuado para estos escenarios:</p><ul><li>Tienes múltiples clientes/SDK de IA y quieres que pasen por un único Base URL</li><li>Necesitas converger diferentes protocolos (OpenAI/Anthropic/Gemini) en el mismo conjunto de «salida local»</li><li>Tienes múltiples cuentas y quieres que el sistema se encargue de la rotación y el manejo de estabilidad</li></ul><p>Si solo quieres «escribir dos líneas de código y llamar directamente a la API oficial», y las cuentas/protocolos son muy fijos, puede que sea un poco pesado.</p><h2 id="sigueme-primero-establece-un-orden-de-uso-correcto" tabindex="-1">Sígueme: primero establece un orden de uso correcto <a class="header-anchor" href="#sigueme-primero-establece-un-orden-de-uso-correcto" aria-label="Permalink to &quot;Sígueme: primero establece un orden de uso correcto&quot;">​</a></h2><p>Esta lección no te enseña la configuración detallada, solo alinea el orden principal para evitar que te quedes atascado por saltar pasos:</p><h3 id="paso-1-primero-instala-y-luego-inicia" tabindex="-1">Paso 1: Primero instala y luego inicia <a class="header-anchor" href="#paso-1-primero-instala-y-luego-inicia" aria-label="Permalink to &quot;Paso 1: Primero instala y luego inicia&quot;">​</a></h3><p><strong>Por qué</strong> El lado de escritorio se encarga de la gestión de cuentas e iniciar el servicio de proxy inverso; sin él, no se puede hablar del OAuth/proxy inverso posterior.</p><p>Ve al siguiente capítulo y completa la instalación según el método de README.</p><p><strong>Deberías ver</strong>: Puedes abrir Antigravity Tools y ver la página Dashboard.</p><h3 id="paso-2-agrega-al-menos-una-cuenta" tabindex="-1">Paso 2: Agrega al menos una cuenta <a class="header-anchor" href="#paso-2-agrega-al-menos-una-cuenta" aria-label="Permalink to &quot;Paso 2: Agrega al menos una cuenta&quot;">​</a></h3><p><strong>Por qué</strong> El servicio de proxy inverso necesita obtener una identidad disponible del pool de cuentas para enviar solicitudes al upstream; sin cuentas, la puerta de enlace tampoco puede «llamar en tu nombre».</p><p>Ve al capítulo «Agregar cuenta» y añade la cuenta mediante el flujo OAuth o Refresh Token.</p><p><strong>Deberías ver</strong>: Tu cuenta aparece en la página Accounts, y puedes ver información de cuota/estado.</p><h3 id="paso-3-inicia-api-proxy-y-haz-una-verificacion-minima-con-healthz" tabindex="-1">Paso 3: Inicia API Proxy y haz una verificación mínima con /healthz <a class="header-anchor" href="#paso-3-inicia-api-proxy-y-haz-una-verificacion-minima-con-healthz" aria-label="Permalink to &quot;Paso 3: Inicia API Proxy y haz una verificación mínima con /healthz&quot;">​</a></h3><p><strong>Por qué</strong> Primero usa <code>GET /healthz</code> para verificar «el servicio local está ejecutándose», y luego conecta el cliente, lo que facilitará mucho la solución de problemas.</p><p>Ve al capítulo «Iniciar proxy inverso local y conectar el primer cliente» para completar el ciclo cerrado.</p><p><strong>Deberías ver</strong>: Tu cliente/SDK puede obtener con éxito una respuesta a través de la Base URL local.</p><h2 id="advertencias-sobre-problemas-comunes" tabindex="-1">Advertencias sobre problemas comunes <a class="header-anchor" href="#advertencias-sobre-problemas-comunes" aria-label="Permalink to &quot;Advertencias sobre problemas comunes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Escenario</th><th>Qué podrías hacer (❌)</th><th>Enfoque recomendado (✓)</th></tr></thead><tbody><tr><td>Permitir que el teléfono/otra computadora acceda</td><td>Habilitar directamente <code>allow_lan_access=true</code> sin establecer autenticación</td><td>Habilitar la autenticación al mismo tiempo, y primero verificar <code>GET /healthz</code> en la red de área local</td></tr><tr><td>El cliente informa 404</td><td>Solo cambiar host/port, sin importar cómo el cliente concatena <code>/v1</code></td><td>Primero confirmar la estrategia de concatenación base_url del cliente, luego decidir si es necesario llevar el prefijo <code>/v1</code></td></tr><tr><td>Empiezas directamente a depurar con Claude Code</td><td>Conectar directamente un cliente complejo, sin saber dónde verificar cuando falla</td><td>Primero ejecutar el ciclo cerrado mínimo: iniciar Proxy -&gt; <code>GET /healthz</code> -&gt; luego conectar el cliente</td></tr></tbody></table><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li>El posicionamiento de Antigravity Tools es «lado de escritorio + puerta de enlace de proxy inverso HTTP local»: gestión mediante GUI, Axum proporciona múltiples puntos finales de protocolo</li><li>Necesitas tratarlo como una infraestructura local: primero instala, luego agrega cuentas, luego inicia Proxy, finalmente conecta el cliente</li><li>Por defecto solo escucha en <code>127.0.0.1:8045</code>, si necesitas exponer a la red de área local, asegúrate de activar la autenticación</li></ul><h2 id="proximo-capitulo" tabindex="-1">Próximo capítulo <a class="header-anchor" href="#proximo-capitulo" aria-label="Permalink to &quot;Próximo capítulo&quot;">​</a></h2><blockquote><p>En el siguiente capítulo completaremos el paso de instalación: <strong><a href="/docs/opencodedocs/es/lbjlaq/Antigravity-Manager/start/installation/">Instalación y actualización: la mejor ruta de instalación de escritorio</a></strong>.</p><p>Aprenderás:</p><ul><li>Los varios métodos de instalación listados en README (y su prioridad)</li><li>El punto de entrada de actualización y cómo manejar las intercepciones comunes del sistema</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver las ubicaciones del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Posicionamiento del producto (estación de transferencia de IA local / brecha de protocolos)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L35-L77" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>35-77</td></tr><tr><td>Visión general de puntos finales del Router (OpenAI/Claude/Gemini/healthz)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>Lógica de puerto predeterminado / solo local predeterminado / key predeterminado y bind address</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Estructura de enrutamiento de páginas GUI (Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>Valores predeterminados clave</strong>:</p><ul><li><code>ProxyConfig.port = 8045</code>: puerto predeterminado del servicio de proxy inverso</li><li><code>ProxyConfig.allow_lan_access = false</code>: acceso solo local predeterminado</li><li><code>ProxyAuthMode::default() = off</code>: no requiere autenticación por defecto</li></ul></details>',55)])])}const g=a(r,[["render",n]]);export{m as __pageData,g as default};
